const BUNDLE_ID = "cassius-presence-vampire-cr18";
const ACTOR_NAME = "Кассиус, Алая Муза [CR 18]";
const AVATAR = "assets/cassius-presence-avatar.png";
const TOKEN = "assets/cassius-presence-token.png";
const SAVE_DC = 20;

function clone(data) {
  return foundry.utils.deepClone(data);
}

function asset(bundle, localPath) {
  return bundle?.assets?.[localPath] ?? `modules/ai-patcher/inbox/${BUNDLE_ID}/${localPath}`;
}

function activityValues(activities) {
  if (!activities) return [];
  if (activities.contents) return activities.contents;
  if (activities.values) return Array.from(activities.values());
  return Object.values(activities);
}

function macroFlags(name, command, passes) {
  return {
    itemacro: {
      macro: {
        name,
        type: "script",
        img: "icons/magic/control/hypnosis-mesmerism-eye.webp",
        scope: "global",
        command,
        author: game.user.id,
        ownership: { default: 0, [game.user.id]: 3 }
      }
    },
    "midi-qol": { onUseMacroName: `${name},${passes}` }
  };
}

const PRESENCE_HELPERS = `
function sourceSpeaker(selfActor) {
  return ChatMessage.getSpeaker({ actor: selfActor ?? actor, token: token?.document ?? token });
}
function tokenDistance(a, b) {
  if (!a || !b) return Infinity;
  if (canvas.grid?.measurePath) {
    const path = canvas.grid.measurePath([a.center, b.center]);
    return Number(path?.distance ?? Infinity);
  }
  const dx = a.center.x - b.center.x;
  const dy = a.center.y - b.center.y;
  return Math.hypot(dx, dy) / canvas.grid.size * (canvas.scene.grid.distance || 5);
}
function hostileTokensInRange(range) {
  const selfToken = token ?? canvas.tokens.controlled[0] ?? canvas.tokens.placeables.find(t => t.actor?.id === actor?.id);
  return canvas.tokens.placeables.filter(t =>
    t.actor &&
    t.id !== selfToken?.id &&
    !t.document.hidden &&
    t.document.disposition !== selfToken?.document?.disposition &&
    tokenDistance(selfToken, t) <= range
  );
}
async function applyEffect(targetActor, data) {
  const old = targetActor.effects.filter(e => e.getFlag("ai-patcher", data.flag));
  if (old.length) await targetActor.deleteEmbeddedDocuments("ActiveEffect", old.map(e => e.id));
  await targetActor.createEmbeddedDocuments("ActiveEffect", [{
    name: data.name,
    icon: data.icon,
    origin: item?.uuid,
    duration: data.duration ?? { rounds: 10 },
    statuses: data.statuses ?? [],
    changes: data.changes ?? [],
    description: data.description ?? "",
    flags: {
      "ai-patcher": { [data.flag]: true, bundleId: "${BUNDLE_ID}" },
      dae: data.dae ?? {}
    }
  }]);
}
`;

const AWE_MACRO = `${PRESENCE_HELPERS}
const data = args?.[0] ?? {};
const wf = data.workflow ?? globalThis.workflow;
if (data.macroPass === "preTargeting") {
  const targets = hostileTokensInRange(30);
  if (!targets.length) return ui.notifications?.warn("Благоговение: нет врагов в 30 фт.");
  game.user.updateTokenTargets(targets.map(t => t.id));
  if (wf) wf.targets = new Set(targets);
}
if (data.macroPass !== "postActiveEffects") return;
const failed = Array.from(wf?.failedSaves ?? []);
for (const target of failed) {
  if (!target.actor) continue;
  await applyEffect(target.actor, {
    name: "Благоговение",
    icon: item.img,
    flag: "cassiusAwe",
    statuses: ["charmed"],
    duration: { rounds: 10 },
    changes: [
      { key: "flags.midi-qol.disadvantage.attack.all", mode: CONST.ACTIVE_EFFECT_MODES.CUSTOM, value: "1", priority: 20 }
    ],
    description: "Цель очарована Кассиусом и совершает атаки с помехой, пока эффект не закончится."
  });
}
if (failed.length) await ChatMessage.create({ speaker: sourceSpeaker(actor), content: \`<p><strong>Благоговение.</strong> Очаровано целей: <strong>\${failed.length}</strong>.</p>\` });`;

const DREAD_MACRO = `${PRESENCE_HELPERS}
const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const failed = Array.from((data.workflow ?? globalThis.workflow)?.failedSaves ?? []);
for (const target of failed) {
  if (!target.actor) continue;
  await applyEffect(target.actor, {
    name: "Устрашающий взгляд",
    icon: item.img,
    flag: "cassiusDreadGaze",
    statuses: ["frightened"],
    duration: { rounds: 2 },
    changes: [
      { key: "flags.midi-qol.disadvantage.attack.all", mode: CONST.ACTIVE_EFFECT_MODES.CUSTOM, value: "1", priority: 20 }
    ],
    description: "Цель испугана Кассиусом. Повторный спасбросок Мдр СЛ 20 в конце каждого хода прекращает эффект."
  });
}
if (failed.length) await ChatMessage.create({ speaker: sourceSpeaker(actor), content: \`<p><strong>Устрашающий взгляд.</strong> Испугано целей: <strong>\${failed.length}</strong>.</p>\` });`;

const ENTRANCEMENT_MACRO = `${PRESENCE_HELPERS}
const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const failed = Array.from((data.workflow ?? globalThis.workflow)?.failedSaves ?? []);
for (const target of failed) {
  if (!target.actor) continue;
  await applyEffect(target.actor, {
    name: "Восторг",
    icon: item.img,
    flag: "cassiusEntrancement",
    statuses: ["charmed"],
    duration: { seconds: 3600 },
    description: "Цель очарована Кассиусом, считает его объектом восхищения и выполняет не самоубийственные просьбы. Эффект заканчивается, если Кассиус или его союзники причиняют цели вред."
  });
}
if (failed.length) await ChatMessage.create({ speaker: sourceSpeaker(actor), content: \`<p><strong>Восторг.</strong> Восхищены и подчинены целей: <strong>\${failed.length}</strong>.</p>\` });`;

const SUMMON_MACRO = `${PRESENCE_HELPERS}
const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const targets = Array.from(game.user.targets ?? []).filter(t => t.actor);
if (!targets.length) {
  await ChatMessage.create({ speaker: sourceSpeaker(actor), content: "<p><strong>Призыв.</strong> Выберите цели, которых Кассиус зовёт своим Присутствием. На расстоянии за пределами сцены эффект отмечается повествовательно.</p>" });
  return;
}
for (const target of targets) {
  await applyEffect(target.actor, {
    name: "Призыв Кассиуса",
    icon: item.img,
    flag: "cassiusSummon",
    statuses: ["charmed"],
    duration: { hours: 24 },
    description: "Цель чувствует непреодолимую потребность явиться к Кассиусу кратчайшим разумным путём."
  });
}
await ChatMessage.create({ speaker: sourceSpeaker(actor), content: \`<p><strong>Призыв.</strong> Позваны цели: <strong>\${targets.map(t => t.name).join(", ")}</strong>.</p>\` });`;

const MAJESTY_MACRO = `${PRESENCE_HELPERS}
const data = args?.[0] ?? {};
const wf = data.workflow ?? globalThis.workflow;
if (data.macroPass === "preTargeting") {
  const targets = hostileTokensInRange(30);
  if (!targets.length) return ui.notifications?.warn("Величие: нет врагов в 30 фт.");
  game.user.updateTokenTargets(targets.map(t => t.id));
  if (wf) wf.targets = new Set(targets);
}
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? wf?.actor;
if (selfActor) {
  await applyEffect(selfActor, {
    name: "Величие",
    icon: item.img,
    flag: "cassiusMajestySelf",
    duration: { rounds: 10 },
    description: "Кассиус окружён сверхъестественным величием. Враги в 30 фт должны преодолеть его Присутствие, чтобы действовать против него."
  });
}
const failed = Array.from(wf?.failedSaves ?? []);
for (const target of failed) {
  if (!target.actor) continue;
  await applyEffect(target.actor, {
    name: "Подавлен Величием",
    icon: item.img,
    flag: "cassiusMajestyTarget",
    statuses: ["charmed"],
    duration: { rounds: 10 },
    changes: [
      { key: "flags.midi-qol.disadvantage.attack.all", mode: CONST.ACTIVE_EFFECT_MODES.CUSTOM, value: "1", priority: 20 },
      { key: "flags.midi-qol.fail.ability.save.wis", mode: CONST.ACTIVE_EFFECT_MODES.CUSTOM, value: "0", priority: 20 }
    ],
    description: "Цель не может добровольно атаковать Кассиуса или выбрать его целью вредоносного эффекта. Если автоматизация не блокирует действие, считайте это обязательным ограничением."
  });
}
await ChatMessage.create({ speaker: sourceSpeaker(selfActor), content: \`<p><strong>Величие.</strong> Аура активна. Подавлено целей: <strong>\${failed.length}</strong>.</p>\` });`;

const BITE_HEAL_MACRO = `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? data.workflow?.actor;
if (!selfActor) return;
const hp = selfActor.system.attributes.hp;
const healed = Math.min(20, Number(hp.max ?? 0) - Number(hp.value ?? 0));
if (healed > 0) await selfActor.update({ "system.attributes.hp.value": Number(hp.value ?? 0) + healed });
await ChatMessage.create({ speaker: ChatMessage.getSpeaker({ actor: selfActor, token: token?.document ?? token }), content: \`<p><strong>Кровавый поцелуй.</strong> Кассиус восстанавливает <strong>\${healed}</strong> хитов.</p>\` });`;

const SUNLIGHT_MACRO = `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? data.workflow?.actor;
if (!selfActor) return;
const damage = 20;
const selfToken = token ?? canvas.tokens.placeables.find(t => t.actor?.id === selfActor.id);
if (game.modules.get("midi-qol")?.active && MidiQOL?.applyTokenDamage && selfToken) {
  await MidiQOL.applyTokenDamage([{ damage, type: "radiant" }], damage, new Set([selfToken]), item, new Set([selfToken]), { flavor: "Чувствительность к солнечному свету" });
} else {
  const hp = selfActor.system.attributes.hp;
  await selfActor.update({ "system.attributes.hp.value": Math.max(0, Number(hp.value ?? 0) - damage) });
}
await ChatMessage.create({ speaker: ChatMessage.getSpeaker({ actor: selfActor, token: selfToken?.document ?? selfToken }), content: "<p><strong>Чувствительность к солнечному свету.</strong> Кассиус получает <strong>20 урона излучением</strong>.</p>" });`;

const MULTIATTACK_MACRO = `const data = args?.[0] ?? {};
if (data.macroPass !== "postActiveEffects") return;
const selfActor = actor ?? data.workflow?.actor;
const targets = Array.from(game.user.targets ?? []).filter(t => t.actor);
if (!selfActor || !targets.length) return ui.notifications?.warn("Мультиатака: выберите хотя бы одну цель.");
function activityValues(activities) {
  if (!activities) return [];
  if (activities.contents) return activities.contents;
  if (activities.values) return Array.from(activities.values());
  return Object.values(activities);
}
async function useNamed(name, target) {
  const found = selfActor.items.find(i => i.name === name);
  const activity = activityValues(found?.system.activities)[0];
  if (!activity) return ui.notifications?.warn(\`Мультиатака: не найдена активность \${name}.\`);
  await MidiQOL.completeActivityUse(activity, {
    midiOptions: {
      targetUuids: [target.document.uuid],
      targetsToUse: new Set([target]),
      ignoreUserTargets: true,
      configureDialog: false,
      workflowOptions: { targetConfirmation: "none" },
      fastForward: true,
      fastForwardAttack: true,
      fastForwardDamage: true
    }
  }, {}, {});
}
const target = targets[0];
await ChatMessage.create({ speaker: ChatMessage.getSpeaker({ actor: selfActor, token: token?.document ?? token }), content: "<p><strong>Мультиатака.</strong> Кассиус совершает две атаки Сабельным когтем и один Кровавый поцелуй.</p>" });
await useNamed("Сабельный коготь", target);
await useNamed("Сабельный коготь", targets[1] ?? target);
await useNamed("Кровавый поцелуй", targets[2] ?? target);`;

