    name: ACTOR_NAME,
    type: "npc",
    img: asset(bundle, AVATAR),
    system: {
      abilities: {
        str: { value: 18, proficient: 1, bonuses: { check: "", save: "" } },
        dex: { value: 22, proficient: 1, bonuses: { check: "", save: "" } },
        con: { value: 20, proficient: 1, bonuses: { check: "", save: "" } },
        int: { value: 18, proficient: 0, bonuses: { check: "", save: "" } },
        wis: { value: 20, proficient: 1, bonuses: { check: "", save: "" } },
        cha: { value: 24, proficient: 1, bonuses: { check: "", save: "+1" } }
      },
      attributes: {
        ac: { flat: 18, calc: "flat" },
        hp: { value: 255, max: 255, temp: 0, tempmax: 0, formula: "30d8 + 120" },
        movement: { walk: 40, climb: 30, units: "ft" },
        senses: { units: "ft", special: "", ranges: { darkvision: 120, blindsight: null, tremorsense: null, truesight: null } },
        spellcasting: "cha"
      },
      skills: {
        dec: { value: 2, ability: "cha", bonuses: { check: "+1", passive: "" } },
        ins: { value: 1, ability: "wis", bonuses: { check: "+1", passive: "" } },
        per: { value: 2, ability: "cha", bonuses: { check: "+1", passive: "" } },
        prf: { value: 2, ability: "cha", bonuses: { check: "+1", passive: "" } },
