function baseItem(name, img, description) {
  return {
    name,
    type: "feat",
    img,
    system: {
      description: { value: description, chat: "" },
      source: { revision: 1, rules: "2024", custom: "AI Patcher" },
      uses: { spent: 0, recovery: [], max: "" },
      activities: {},
      type: { value: "monster", subtype: "" },
      properties: []
    },
    flags: { "ai-patcher": { bundleId: BUNDLE_ID }, world: { cassiusPresenceVampireCR18: true } },
    effects: [],
    ownership: { default: 0, [game.user.id]: 3 }
  };
}

function addAttackActivity(item, { activityName, activation = "action", reach = 5, ability = "dex", attackBonus = "+1", damageParts = [] }) {
  const source = clone(item);
  source.system.actionType = "mwak";
  source.system.activation = { type: activation, cost: 1, condition: "" };
  source.system.attack = { bonus: attackBonus, flat: false };
  source.system.ability = ability;
  source.system.range = { value: null, long: null, reach, units: "ft" };
  source.system.target = { value: 1, type: "creature", units: "", prompt: true };
  source.system.damage = { parts: damageParts };
  CONFIG.DND5E.activityTypes.attack.documentClass.createInitialActivity(source, { offset: 0 });
  const activity = activityValues(source.system.activities)[0];
  activity.name = activityName;
  item.system.activities = source.system.activities;
}

function addSaveActivity(item, { activityName, activation = "action", range = 60, ability = "wis", prompt = true }) {
  const source = clone(item);
  source.system.actionType = "save";
  source.system.activation = { type: activation, cost: 1, condition: "" };
  source.system.range = { value: range, units: "ft" };
  source.system.target = { value: null, type: "creature", units: "", prompt };
  source.system.save = { ability, dc: SAVE_DC, scaling: "flat" };
  source.system.damage = { parts: [] };
  CONFIG.DND5E.activityTypes.save.documentClass.createInitialActivity(source, { offset: 0 });
  const activity = activityValues(source.system.activities)[0];
  activity.name = activityName;
  if (activity.target) activity.target.prompt = prompt;
  item.system.activities = source.system.activities;
}

function addUtilityActivity(item, { activityName, activation = "action" }) {
  const source = clone(item);
  source.system.activation = { type: activation, cost: 1, condition: "" };
  CONFIG.DND5E.activityTypes.utility.documentClass.createInitialActivity(source, { offset: 0 });
  const activity = activityValues(source.system.activities)[0];
  activity.name = activityName;
  item.system.activities = source.system.activities;
}

function buildItems() {
  const items = [];

  const multi = baseItem("Мультиатака", "icons/skills/melee/strike-sword-slashing-red.webp", "<p>Кассиус совершает две атаки <strong>Сабельным когтем</strong> и один <strong>Кровавый поцелуй</strong>. Макрос автоматически разыгрывает атаки по выбранным целям.</p>");
  addUtilityActivity(multi, { activityName: "Мультиатака" });
  multi.flags = { ...multi.flags, ...macroFlags("Мультиатака Кассиуса ItemMacro", MULTIATTACK_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(multi);

  const claw = baseItem("Сабельный коготь", "icons/skills/melee/strike-sword-blood-red.webp", "<p><strong>Рукопашная атака оружием:</strong> +12 к попаданию, досягаемость 5 фт, одна цель. Урон: 2d8 + 6 рубящий + 2d8 психический.</p>");
  addAttackActivity(claw, { activityName: "Сабельный коготь", damageParts: [["2d8 + 6", "slashing"], ["2d8", "psychic"]] });
  items.push(claw);

  const bite = baseItem("Кровавый поцелуй", "icons/creatures/abilities/fang-tooth-blood-red.webp", "<p><strong>Рукопашная атака оружием:</strong> +12 к попаданию, досягаемость 5 фт, одна цель. Урон: 1d10 + 6 колющий + 4d8 некротический. Кассиус восстанавливает 20 хитов.</p>");
  addAttackActivity(bite, { activityName: "Кровавый поцелуй", damageParts: [["1d10 + 6", "piercing"], ["4d8", "necrotic"]] });
  bite.flags = { ...bite.flags, ...macroFlags("Кровавый поцелуй ItemMacro", BITE_HEAL_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(bite);

  const sunlight = baseItem("Чувствительность к солнечному свету", "icons/magic/light/explosion-star-glow-yellow.webp", "<p>Находясь под прямым солнечным светом, Кассиус получает 20 урона излучением в начале своего хода. Пока он находится на солнечном свету, он совершает броски атаки и проверки характеристик с помехой. Нажмите способность в начале хода, если он под солнцем.</p>");
  addUtilityActivity(sunlight, { activityName: "Солнечный ожог" });
  sunlight.flags = { ...sunlight.flags, ...macroFlags("Солнечный ожог Кассиуса ItemMacro", SUNLIGHT_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(sunlight);

  const awe = baseItem("Присутствие I: Благоговение", "icons/magic/control/silhouette-aura-energy.webp", "<p>Кассиус раскрывает хищную красоту. Все враги в 30 фт автоматически выбираются макросом и совершают спасбросок Мдр СЛ 20. При провале цель очарована на 1 минуту и атакует с помехой.</p>");
  addSaveActivity(awe, { activityName: "Благоговение", range: 30, prompt: false });
  awe.flags = { ...awe.flags, ...macroFlags("Благоговение ItemMacro", AWE_MACRO, "[preTargeting]ItemMacro,[postActiveEffects]ItemMacro") };
  items.push(awe);

  const dread = baseItem("Присутствие II: Устрашающий взгляд", "icons/magic/control/fear-fright-monster-red.webp", "<p>Одна цель в 60 фт совершает спасбросок Мдр СЛ 20. При провале цель испугана Кассиусом на 2 раунда и повторяет спасбросок в конце каждого хода.</p>");
  addSaveActivity(dread, { activityName: "Устрашающий взгляд", range: 60 });
  dread.flags = { ...dread.flags, ...macroFlags("Устрашающий взгляд ItemMacro", DREAD_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(dread);

  const entrancement = baseItem("Присутствие III: Восторг", "icons/magic/control/control-influence-crown-gold.webp", "<p>Одна цель в 60 фт совершает спасбросок Мдр СЛ 20. При провале она очарована на 1 час, восхищается Кассиусом и выполняет не самоубийственные просьбы. Эффект заканчивается, если Кассиус или союзники вредят цели.</p>");
  addSaveActivity(entrancement, { activityName: "Восторг", range: 60 });
  entrancement.flags = { ...entrancement.flags, ...macroFlags("Восторг ItemMacro", ENTRANCEMENT_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(entrancement);

  const summon = baseItem("Присутствие IV: Призыв", "icons/magic/control/control-influence-puppet.webp", "<p>Кассиус зовёт тех, кто уже оказался связан его образом. Выберите цели на сцене: макрос наложит эффект зова на 24 часа. Вне сцены эффект используется повествовательно и фиксируется сообщением в чат.</p>");
  addUtilityActivity(summon, { activityName: "Призыв" });
  summon.flags = { ...summon.flags, ...macroFlags("Призыв ItemMacro", SUMMON_MACRO, "[postActiveEffects]ItemMacro") };
  items.push(summon);

  const majesty = baseItem("Присутствие V: Величие", "icons/magic/control/silhouette-hold-change-blue.webp", "<p>На 1 минуту Кассиус становится почти неприкосновенным объектом преклонения. Макрос автоматически выбирает врагов в 30 фт; при провале спасброска Мдр СЛ 20 цель не может добровольно атаковать Кассиуса или выбрать его целью вредоносного эффекта.</p>");
  addSaveActivity(majesty, { activityName: "Величие", range: 30, prompt: false });
  majesty.flags = { ...majesty.flags, ...macroFlags("Величие ItemMacro", MAJESTY_MACRO, "[preTargeting]ItemMacro,[postActiveEffects]ItemMacro") };
  items.push(majesty);

  return items;
}

export default async function patch({ dryRun, log, bundle }) {
  if (game.system.id !== "dnd5e") throw new Error("Кассиус создан для системы dnd5e.");

  const existing = game.actors.find((actor) =>
    actor.getFlag("ai-patcher", "bundleId") === BUNDLE_ID ||
    actor.name === ACTOR_NAME
  );
  const actorData = baseActorData(bundle);
  const itemData = buildItems();

  if (dryRun) {
    return {
      action: existing ? "update actor and replace Cassius items" : "create actor",
      actor: ACTOR_NAME,
      cr: 18,
      items: itemData.map((item) => item.name),
      avatar: asset(bundle, AVATAR),
      token: asset(bundle, TOKEN)
    };
  }

  let actor = existing;
  if (actor) {
    log(`Updating actor: ${actor.name}`);
    await actor.update(actorData);
    const oldItems = actor.items.filter((item) => item.getFlag("ai-patcher", "bundleId") === BUNDLE_ID);
    if (oldItems.length) await actor.deleteEmbeddedDocuments("Item", oldItems.map((item) => item.id));
    await actor.createEmbeddedDocuments("Item", itemData);
  } else {
    log(`Creating actor: ${ACTOR_NAME}`);
    actorData.items = itemData;
    actor = await Actor.create(actorData);
  }

  await actor.setFlag("ai-patcher", "bundleId", BUNDLE_ID);
  return { actor: actor.uuid, name: actor.name, itemCount: actor.items.size, token: actor.prototypeToken.texture.src };
}
